SELECT id, express_no, user_id, user_name, user_phone, user_room, express_company, station_status, storage_time, pick_time, operator, create_by, create_time, update_by, update_time, remark
FROM community_station
WHERE express_no = #{expressNo}
  AND user_id = #{userId}
  AND user_name LIKE CONCAT('%', #{userName}, '%')
  AND user_phone = #{userPhone}
  AND user_room = #{userRoom}
  AND express_company = #{expressCompany}
  AND station_status = #{stationStatus}
  AND storage_time = #{storageTime}
  AND pick_time = #{pickTime}
  AND operator = #{operator}

SELECT id, express_no, user_id, user_name, user_phone, user_room, express_company, station_status, storage_time, pick_time, operator, create_by, create_time, update_by, update_time, remark
FROM community_station
WHERE id = #{id}
